mapper.select:
/* ---- 项目+费项 细粒度 ---- */ SELECT r.project_id AS projectId, COALESCE(r.fee_item_id, 0) AS feeItemId, MAX(r.fee_name) AS feeItemType,
/* 应收（本月权责月范围内的实际应收） */ SUM(COALESCE(r.actual_amount, 0)) AS receivableAmount,
/* 已收 */ SUM(COALESCE(r.received_amount, 0)) AS receivedAmount,
/* 逾期金额（已过期且未全额收清） */ SUM(CASE WHEN r.due_date IS NOT NULL AND r.due_date < DATE_ADD(DATE_FORMAT(#{statMonth}, '%Y-%m-01'), INTERVAL 1 MONTH) AND r.status IN (0, 1) /* 待收/部分收款 */ THEN COALESCE(r.outstanding_amount, 0) ELSE 0 END) AS overdueAmount,
/* 减免合计 */ SUM(COALESCE(r.deduction_amount, 0)) AS deductionAmount,
/* 调整合计 */ SUM(COALESCE(r.adjust_amount, 0)) AS adjustmentAmount
FROM asset_db.fin_receivable r WHERE r.is_deleted = 0 AND r.accrual_month = #{statMonth} AND r.project_id IS NOT NULL
GROUP BY r.project_id, COALESCE(r.fee_item_id, 0)
/* ---- 项目级全费项汇总行（feeItemId=0） ---- */ UNION ALL SELECT r.project_id, 0 AS feeItemId, '' AS feeItemType, SUM(COALESCE(r.actual_amount, 0)), SUM(COALESCE(r.received_amount, 0)), SUM(CASE WHEN r.due_date IS NOT NULL AND r.due_date < DATE_ADD(DATE_FORMAT(#{statMonth}, '%Y-%m-01'), INTERVAL 1 MONTH) AND r.status IN (0, 1) THEN COALESCE(r.outstanding_amount, 0) ELSE 0 END), SUM(COALESCE(r.deduction_amount, 0)), SUM(COALESCE(r.adjust_amount, 0)) FROM asset_db.fin_receivable r WHERE r.is_deleted = 0 AND r.accrual_month = #{statMonth} AND r.project_id IS NOT NULL GROUP BY r.project_id
